import React, { useState, useEffect, useRef } from 'react';
import { motion, useScroll, useTransform, AnimatePresence } from 'framer-motion';
import {
  ArrowRightIcon,
  CheckBadgeIcon,
  ChartBarIcon,
  ChatBubbleLeftRightIcon,
  ShieldCheckIcon,
  UserGroupIcon,
  DocumentTextIcon,
  GlobeAltIcon,
  ClockIcon,
  StarIcon,
  ChevronRightIcon,
  PlayIcon,
  SparklesIcon,
  FingerPrintIcon,
  MapPinIcon,
} from '@heroicons/react/24/outline';
import { Link } from 'react-router-dom';
import CountUp from 'react-countup';
import { useInView } from 'react-intersection-observer';

/* ─────────────────────────────────────────────────────────────
   Sri Lanka landmark images (Unsplash, no-referrer safe)
   Each has a primary URL + a picsum fallback seed
───────────────────────────────────────────────────────────── */
const SL_PLACES = [
  {
    name: 'Sigiriya Rock Fortress',
    region: 'Central Province',
    url: 'https://images.unsplash.com/photo-1586974373029-622f76ab25fa?auto=format&fit=crop&w=1600&q=85',
    fallback: 'https://picsum.photos/seed/sigiriya/1600/900',
  },
  {
    name: 'Temple of the Tooth, Kandy',
    region: 'Kandy',
    url: 'https://images.unsplash.com/photo-1510001618818-4b4e3d86bf0f?auto=format&fit=crop&w=1600&q=85',
    fallback: 'https://picsum.photos/seed/kandy/1600/900',
  },
  {
    name: 'Colombo City Skyline',
    region: 'Western Province',
    url: 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?auto=format&fit=crop&w=1600&q=85',
    fallback: 'https://picsum.photos/seed/colombo/1600/900',
  },
  {
    name: 'Galle Dutch Fort',
    region: 'Southern Province',
    url: 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?auto=format&fit=crop&w=1600&q=85',
    fallback: 'https://picsum.photos/seed/galle/1600/900',
  },
  {
    name: 'Ella Tea Country',
    region: 'Uva Province',
    url: 'https://images.unsplash.com/photo-1560963689-b5682b6440f8?auto=format&fit=crop&w=1600&q=85',
    fallback: 'https://picsum.photos/seed/ella/1600/900',
  },
];

/* Smaller landmark images for section backgrounds */
const SECTION_PLACES = [
  {
    name: 'Yala National Park',
    url: 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?auto=format&fit=crop&w=900&q=80',
    fallback: 'https://picsum.photos/seed/yala/900/600',
  },
  {
    name: 'Dambulla Cave Temple',
    url: 'https://images.unsplash.com/photo-1518548419970-58e3b4079ab2?auto=format&fit=crop&w=900&q=80',
    fallback: 'https://picsum.photos/seed/dambulla/900/600',
  },
  {
    name: 'Mirissa Beach',
    url: 'https://images.unsplash.com/photo-1559494007-9f5847c49d94?auto=format&fit=crop&w=900&q=80',
    fallback: 'https://picsum.photos/seed/mirissa/900/600',
  },
];

/* ─── Safe image component with fallback ───────────────────── */
const SafeImg = ({ src, fallback, alt, style, className }) => {
  const [err, setErr] = useState(false);
  return (
    <img
      src={err ? fallback : src}
      alt={alt || ''}
      referrerPolicy="no-referrer"
      crossOrigin="anonymous"
      onError={() => setErr(true)}
      style={style}
      className={className}
    />
  );
};

/* ─── Hero background slideshow ───────────────────────────── */
const HeroSlideshow = () => {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const t = setInterval(() => setCurrent(c => (c + 1) % SL_PLACES.length), 5000);
    return () => clearInterval(t);
  }, []);

  return (
    <div className="absolute inset-0 z-0">
      {SL_PLACES.map((place, i) => (
        <AnimatePresence key={i}>
          {i === current && (
            <motion.div
              key={`slide-${i}`}
              className="absolute inset-0"
              initial={{ opacity: 0, scale: 1.05 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.4, ease: 'easeInOut' }}
            >
              <SafeImg
                src={place.url}
                fallback={place.fallback}
                alt={place.name}
                className="w-full h-full object-cover"
              />
            </motion.div>
          )}
        </AnimatePresence>
      ))}

      {/* Layered overlays */}
      <div className="absolute inset-0 bg-gradient-to-b from-black/65 via-black/45 to-orange-950/80 z-10" />
      <div className="absolute inset-0 bg-gradient-to-r from-black/30 via-transparent to-black/20 z-10" />

      {/* Current place label */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-20 flex flex-col items-center gap-3">
        <motion.div
          key={current}
          initial={{ opacity: 0, y: 8 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.6 }}
          className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/10 backdrop-blur-sm border border-white/20"
        >
          <MapPinIcon className="w-4 h-4 text-orange-300" />
          <span className="text-white/90 text-sm font-medium">{SL_PLACES[current].name}</span>
          <span className="text-white/50 text-xs">· {SL_PLACES[current].region}</span>
        </motion.div>

        {/* Slide dots */}
        <div className="flex gap-2">
          {SL_PLACES.map((_, i) => (
            <button
              key={i}
              onClick={() => setCurrent(i)}
              className="transition-all duration-300 rounded-full"
              style={{
                width: i === current ? 24 : 8,
                height: 8,
                background: i === current ? '#F59E0B' : 'rgba(255,255,255,0.35)',
                border: 'none',
                cursor: 'pointer',
                padding: 0,
              }}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

/* ─── Stats ─────────────────────────────────────────────────── */
const stats = [
  { id: 1, value: 225,  label: 'Politicians Tracked', icon: UserGroupIcon,           suffix: '+' },
  { id: 2, value: 1247, label: 'Promises Made',        icon: DocumentTextIcon,        suffix: '+' },
  { id: 3, value: 856,  label: 'Promises Kept',        icon: CheckBadgeIcon,          suffix: '+' },
  { id: 4, value: 3452, label: 'Citizen Reports',      icon: ChatBubbleLeftRightIcon, suffix: '+' },
];

const StatSection = () => {
  const [ref, inView] = useInView({ triggerOnce: true, threshold: 0.1 });
  return (
    <div ref={ref} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      {stats.map((stat, idx) => (
        <motion.div
          key={stat.id}
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ delay: idx * 0.1 }}
          whileHover={{ y: -5 }}
          className="bg-white/95 dark:bg-gray-800/95 backdrop-blur-sm rounded-2xl shadow-xl p-6 border border-gray-200 dark:border-gray-700 hover:shadow-2xl transition-all"
        >
          <div className="flex items-center justify-between mb-4">
            <div className="w-12 h-12 rounded-full bg-orange-100 dark:bg-orange-500/20 flex items-center justify-center">
              <stat.icon className="w-6 h-6 text-orange-500" />
            </div>
            <SparklesIcon className="w-5 h-5 text-yellow-500 animate-pulse" />
          </div>
          <div className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
            {inView ? <CountUp end={stat.value} duration={2.5} /> : 0}
            {stat.suffix}
          </div>
          <div className="text-gray-600 dark:text-gray-400 text-sm">{stat.label}</div>
        </motion.div>
      ))}
    </div>
  );
};

/* ─── Features ──────────────────────────────────────────────── */
const features = [
  { icon: ShieldCheckIcon,         title: 'Promise Tracking',       description: 'Track political promises with status updates, supporting evidence, and public accountability.', gradient: 'from-blue-500 to-cyan-500',    stats: '95% Accuracy', delay: 0    },
  { icon: ChartBarIcon,            title: 'Performance Analytics',  description: 'View completion rates, politician ratings, and promise fulfillment history.',                   gradient: 'from-purple-500 to-pink-500',  stats: 'Live Updates', delay: 0.1  },
  { icon: GlobeAltIcon,            title: 'News Integration',       description: 'Connect political news and developments with ongoing promises and public feedback.',              gradient: 'from-orange-500 to-red-500',   stats: '24/7 Updates', delay: 0.2  },
  { icon: ChatBubbleLeftRightIcon, title: 'Citizen Feedback',       description: 'Let citizens contribute reports, opinions, and evidence for better transparency.',               gradient: 'from-green-500 to-emerald-500',stats: '10k+ Reviews', delay: 0.3  },
];

/* ─── Politicians ───────────────────────────────────────────── */
const topPoliticians = [
  {
    name: 'Ranil Wickremesinghe', role: 'President of Sri Lanka', party: 'UNP',
    promisesKept: 85, totalPromises: 120, rating: 70.8, trend: '+5.2%', color: '#FF6B35',
    image: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Ranil_Wickremesinghe_2017.jpg/800px-Ranil_Wickremesinghe_2017.jpg',
    place: 'Sri Lankan Parliament',
