      <motion.button
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        whileHover={{ scale: 1.1 }}
        className="fixed bottom-8 right-8 z-50 bg-gradient-to-r from-orange-500 to-red-700 text-white p-4 rounded-full shadow-2xl transition-all"
      >
        <ChatBubbleLeftRightIcon className="w-6 h-6" />
      </motion.button>

    </div>
  );
};

export default Home;
